import React, { useState, useEffect } from 'react';
import { supabase } from './supabaseClient';

function App() {
  const [view, setView] = useState('home');
  const [activeTab, setActiveTab] = useState('confrontos'); 
  const [campeonatos, setCampeonatos] = useState([]);
  const [campeonatoAtivo, setCampeonatoAtivo] = useState(null);
  
  const [times, setTimes] = useState([]);
  const [partidas, setPartidas] = useState([]);
  
  const [nome, setNome] = useState('');
  const [formato, setFormato] = useState('pontos-corridos');
  const [qtdTimes, setQtdTimes] = useState(16);
  
  const [nomeTime, setNomeTime] = useState('');
  const [nomeResponsavel, setNomeResponsavel] = useState('');
  // NOVO: Estado para guardar o arquivo de imagem do escudo
  const [escudoFile, setEscudoFile] = useState(null); 
  const [uploading, setUploading] = useState(false); // Para mostrar "Carregando..."

  const carregarCampeonatos = async () => {
    const { data } = await supabase.from('campeonatos').select('*').order('created_at', { ascending: false });
    if (data) setCampeonatos(data);
  };

  useEffect(() => { carregarCampeonatos(); }, []);

  const carregarTimes = async (id) => {
    const { data } = await supabase.from('times').select('*').eq('campeonato_id', id).order('created_at', { ascending: true });
    if (data) setTimes(data);
  };

  // NOVO: Agora a busca de partidas também traz o escudo dos times!
  const carregarPartidas = async (id) => {
    const { data } = await supabase
      .from('partidas')
      .select(`*, time_casa:time_casa_id(nome, escudo_url), time_fora:time_fora_id(nome, escudo_url)`)
      .eq('campeonato_id', id)
      .order('rodada', { ascending: true });
    if (data) setPartidas(data);
  };

  const abrirDetalhes = (champ) => {
    setCampeonatoAtivo(champ);
    setView('detalhes');
    carregarTimes(champ.id);
    carregarPartidas(champ.id);
  };

  const criarCampeonatoReal = async (e) => {
    e.preventDefault();
    await supabase.from('campeonatos').insert([{ nome, formato, qtd_times: qtdTimes }]);
    carregarCampeonatos(); setView('home');
  };

  // NOVO: Lógica de Upload de Imagem e Criação do Time
  const adicionarTime = async (e) => {
    e.preventDefault();
    if (times.length >= campeonatoAtivo.qtd_times) return alert("Limite atingido!");
    
    setUploading(true);
    let escudoUrl = null;

    // Se o usuário selecionou uma imagem, fazemos o upload primeiro
    if (escudoFile) {
      // Cria um nome único para a imagem para não dar conflito
      const fileExt = escudoFile.name.split('.').pop();
      const fileName = `${Math.random()}.${fileExt}`;
      
      const { data: uploadData, error: uploadError } = await supabase.storage
        .from('escudos')
        .upload(fileName, escudoFile);

      if (uploadError) {
        console.error("Erro no upload", uploadError);
        alert("Erro ao enviar a imagem. O time será salvo sem escudo.");
      } else {
        // Pega a URL pública da imagem que acabou de subir
        const { data: publicUrlData } = supabase.storage.from('escudos').getPublicUrl(fileName);
        escudoUrl = publicUrlData.publicUrl;
      }
    }

    // Salva o time no banco, agora com o escudoUrl (se existir)
    await supabase.from('times').insert([{ 
      campeonato_id: campeonatoAtivo.id, 
      nome: nomeTime, 
      jogador_responsavel: nomeResponsavel,
      escudo_url: escudoUrl // Adicionando a coluna do escudo
    }]);

    // Limpa o formulário
    setNomeTime(''); 
    setNomeResponsavel(''); 
    setEscudoFile(null);
    document.getElementById('fileInput').value = ''; // Reseta o input de arquivo visualmente
    setUploading(false);
    
    carregarTimes(campeonatoAtivo.id);
  };

  const removerTime = async (id) => {
    if (window.confirm("Tens a certeza que queres remover este time?")) {
      await supabase.from('times').delete().eq('id', id);
      carregarTimes(campeonatoAtivo.id);
      carregarPartidas(campeonatoAtivo.id); 
    }
  };

  const gerarTabelaJogos = async () => {
    let timesSorteio = [...times];
    if (timesSorteio.length % 2 !== 0) timesSorteio.push({ id: null, nome: 'FOLGA' });
    const totalRodadas = timesSorteio.length - 1;
    const metade = timesSorteio.length / 2;
    const novasPartidas = [];

    for (let rodada = 1; rodada <= totalRodadas; rodada++) {
      for (let i = 0; i < metade; i++) {
        const casa = timesSorteio[i];
        const fora = timesSorteio[timesSorteio.length - 1 - i];
        if (casa.id && fora.id) {
          novasPartidas.push({ campeonato_id: campeonatoAtivo.id, time_casa_id: casa.id, time_fora_id: fora.id, rodada, status: 'agendado' });
        }
      }
      timesSorteio.splice(1, 0, timesSorteio.pop());
    }
    await supabase.from('partidas').insert(novasPartidas);
    carregarPartidas(campeonatoAtivo.id);
  };

  const atualizarPlacar = async (id, gc, gf) => {
    await supabase.from('partidas').update({ gols_casa: gc, gols_fora: gf, status: 'finalizado' }).eq('id', id);
    carregarPartidas(campeonatoAtivo.id);
  };

  const calcularClassificacao = () => {
    const tabela = times.map(time => {
      let stats = { ...time, p: 0, j: 0, v: 0, e: 0, d: 0, gp: 0, gc: 0, sg: 0 };
      
      partidas.filter(m => m.status === 'finalizado').forEach(m => {
        if (m.time_casa_id === time.id) {
          stats.j++; stats.gp += m.gols_casa; stats.gc += m.gols_fora;
          if (m.gols_casa > m.gols_fora) { stats.v++; stats.p += 3; }
          else if (m.gols_casa === m.gols_fora) { stats.e++; stats.p += 1; }
          else stats.d++;
        } else if (m.time_fora_id === time.id) {
          stats.j++; stats.gp += m.gols_fora; stats.gc += m.gols_casa;
          if (m.gols_fora > m.gols_casa) { stats.v++; stats.p += 3; }
          else if (m.gols_fora === m.gols_casa) { stats.e++; stats.p += 1; }
          else stats.d++;
        }
      });
      stats.sg = stats.gp - stats.gc;
      return stats;
    });

    return tabela.sort((a, b) => b.p - a.p || b.sg - a.sg || b.gp - a.gp);
  };

  return (
    <div className="min-h-screen bg-ef-dark text-white font-sans pb-20">
      <nav className="border-b border-gray-800 p-4 flex justify-between items-center bg-ef-card sticky top-0 z-50">
        <h1 className="text-2xl font-bold italic text-ef-green cursor-pointer" onClick={() => setView('home')}>eFOOTBALL CHAMP</h1>
      </nav>

      <main className="p-8 max-w-7xl mx-auto">
        
        {view === 'home' && (
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            {campeonatos.map(c => (
              <div key={c.id} className="bg-ef-card p-6 rounded-2xl border border-gray-800 hover:border-ef-green transition">
                <h3 className="text-xl font-bold">{c.nome}</h3>
                <button onClick={() => abrirDetalhes(c)} className="mt-4 w-full py-2 bg-ef-green text-black font-bold rounded-lg">Gerenciar</button>
              </div>
            ))}
            <div onClick={() => setView('criar')} className="border-2 border-dashed border-gray-800 p-6 rounded-2xl flex items-center justify-center text-gray-500 cursor-pointer">+ Criar</div>
          </div>
        )}

        {view === 'detalhes' && (
          <div>
            <header className="flex justify-between items-center mb-8">
              <h2 className="text-4xl font-black text-ef-green italic uppercase">{campeonatoAtivo.nome}</h2>
              {partidas.length === 0 && times.length > 1 && (
                <button onClick={gerarTabelaJogos} className="bg-ef-green text-black px-6 py-2 rounded-full font-bold">GERAR TABELA DE JOGOS</button>
              )}
            </header>

            <div className="grid grid-cols-1 lg:grid-cols-4 gap-8">
              <div className="lg:col-span-1 space-y-6">
                
                {/* FORUMULÁRIO COM INPUT DE IMAGEM */}
                <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                  <h4 className="font-bold mb-4">Novo Time</h4>
                  <form onSubmit={adicionarTime} className="space-y-3">
                    <input required value={nomeTime} onChange={e => setNomeTime(e.target.value)} placeholder="Nome do Time" className="w-full bg-ef-dark p-2 rounded border border-gray-700 focus:outline-none focus:border-ef-green" />
                    <input required value={nomeResponsavel} onChange={e => setNomeResponsavel(e.target.value)} placeholder="Jogador" className="w-full bg-ef-dark p-2 rounded border border-gray-700 focus:outline-none focus:border-ef-green" />
                    
                    {/* Botão de Arquivo Personalizado */}
                    <div>
                      <label className="block text-xs text-gray-400 mb-1">Escudo (Opcional)</label>
                      <input 
                        id="fileInput"
                        type="file" 
                        accept="image/*"
                        onChange={e => setEscudoFile(e.target.files[0])}
                        className="w-full text-sm text-gray-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-sm file:font-bold file:bg-gray-800 file:text-ef-green hover:file:bg-gray-700 cursor-pointer"
                      />
                    </div>

                    <button disabled={uploading} className="w-full py-2 bg-ef-green text-black font-bold rounded hover:bg-green-400 transition disabled:opacity-50">
                      {uploading ? 'Salvando...' : 'Adicionar'}
                    </button>
                  </form>
                </div>

                <div className="bg-ef-card p-5 rounded-xl border border-gray-800">
                  <h4 className="font-bold mb-4">Times Cadastrados ({times.length})</h4>
                  <div className="space-y-2">
                    {times.map(t => (
                      <div key={t.id} className="flex justify-between items-center p-2 bg-ef-dark rounded group">
                        
                        {/* MOSTRANDO O ESCUDO NA LISTA */}
                        <div className="flex items-center space-x-3">
                          {t.escudo_url ? (
                            <img src={t.escudo_url} alt="Escudo" className="w-8 h-8 rounded-full object-cover border border-gray-700" />
                          ) : (
                            <div className="w-8 h-8 rounded-full bg-gray-800 border border-gray-700 flex items-center justify-center text-xs text-gray-500">🛡️</div>
                          )}
                          <span className="text-sm font-bold">{t.nome}</span>
                        </div>

                        <button onClick={() => removerTime(t.id)} className="text-red-500 opacity-0 group-hover:opacity-100 transition text-sm">Remover</button>
                      </div>
                    ))}
                  </div>
                </div>
              </div>

              <div className="lg:col-span-3">
                <div className="flex space-x-4 mb-6">
                  <button onClick={() => setActiveTab('confrontos')} className={`px-6 py-2 rounded-full font-bold transition ${activeTab === 'confrontos' ? 'bg-ef-green text-black' : 'bg-gray-800 text-gray-400'}`}>CONFRONTOS</button>
                  <button onClick={() => setActiveTab('tabela')} className={`px-6 py-2 rounded-full font-bold transition ${activeTab === 'tabela' ? 'bg-ef-green text-black' : 'bg-gray-800 text-gray-400'}`}>CLASSIFICAÇÃO</button>
                </div>

                {activeTab === 'confrontos' && (
                  <div className="space-y-8">
                    {partidas.length === 0 ? <p className="text-gray-500">Nenhum jogo gerado.</p> : (
                      [...new Set(partidas.map(p => p.rodada))].map(r => (
                        <div key={r}>
                          <h5 className="text-ef-green font-bold mb-4">RODADA {r}</h5>
                          <div className="space-y-3">
                            {partidas.filter(p => p.rodada === r).map(p => (
                              <div key={p.id} className="flex items-center bg-ef-card p-4 rounded-xl border border-gray-800">
                                
                                {/* ESCUDO E NOME DO TIME CASA */}
                                <div className="flex-1 flex justify-end items-center space-x-3 pr-4">
                                  <span className="font-bold">{p.time_casa?.nome}</span>
                                  {p.time_casa?.escudo_url ? (
                                    <img src={p.time_casa.escudo_url} alt="C" className="w-8 h-8 rounded-full object-cover" />
                                  ) : (
                                    <div className="w-8 h-8 rounded-full bg-gray-800 border border-gray-700"></div>
                                  )}
                                </div>

                                <div className="mx-2 flex space-x-2 bg-black px-4 py-2 rounded-lg border border-gray-800">
                                  <input type="number" defaultValue={p.gols_casa} onBlur={e => atualizarPlacar(p.id, parseInt(e.target.value), p.gols_fora)} className="w-8 bg-transparent text-center font-bold text-ef-green focus:outline-none" />
                                  <span className="text-gray-600">X</span>
                                  <input type="number" defaultValue={p.gols_fora} onBlur={e => atualizarPlacar(p.id, p.gols_casa, parseInt(e.target.value))} className="w-8 bg-transparent text-center font-bold text-ef-green focus:outline-none" />
                                </div>

                                {/* ESCUDO E NOME DO TIME FORA */}
                                <div className="flex-1 flex justify-start items-center space-x-3 pl-4">
                                  {p.time_fora?.escudo_url ? (
                                    <img src={p.time_fora.escudo_url} alt="F" className="w-8 h-8 rounded-full object-cover" />
                                  ) : (
                                    <div className="w-8 h-8 rounded-full bg-gray-800 border border-gray-700"></div>
                                  )}
                                  <span className="font-bold">{p.time_fora?.nome}</span>
                                </div>

                              </div>
                            ))}
                          </div>
                        </div>
                      ))
                    )}
                  </div>
                )}

                {activeTab === 'tabela' && (
                  <div className="bg-ef-card rounded-xl border border-gray-800 overflow-hidden">
                    <table className="w-full text-left">
                      <thead className="bg-gray-800 text-gray-400 text-xs uppercase">
                        <tr>
                          <th className="p-4">Pos</th>
                          <th className="p-4">Clube</th>
                          <th className="p-4 text-center">P</th>
                          <th className="p-4 text-center">J</th>
                          <th className="p-4 text-center">V</th>
                          <th className="p-4 text-center">E</th>
                          <th className="p-4 text-center">D</th>
                          <th className="p-4 text-center">SG</th>
                        </tr>
                      </thead>
                      <tbody>
                        {calcularClassificacao().map((t, i) => (
                          <tr key={t.id} className="border-b border-gray-800 hover:bg-gray-900 transition">
                            <td className="p-4 font-bold">{i + 1}º</td>
                            <td className="p-4 font-bold text-ef-green flex items-center space-x-3">
                               {t.escudo_url ? <img src={t.escudo_url} alt="Escudo" className="w-6 h-6 rounded-full object-cover" /> : <div className="w-6 h-6 rounded-full bg-gray-800"></div>}
                               <span>{t.nome}</span>
                            </td>
                            <td className="p-4 text-center font-black">{t.p}</td>
                            <td className="p-4 text-center text-gray-400">{t.j}</td>
                            <td className="p-4 text-center">{t.v}</td>
                            <td className="p-4 text-center">{t.e}</td>
                            <td className="p-4 text-center">{t.d}</td>
                            <td className="p-4 text-center text-ef-green">{t.sg}</td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  </div>
                )}
              </div>
            </div>
          </div>
        )}

        {view === 'criar' && (
          <div className="max-w-md mx-auto bg-ef-card p-8 rounded-2xl border border-gray-800">
            <h2 className="text-2xl font-bold mb-6">Novo Campeonato</h2>
            <form onSubmit={criarCampeonatoReal} className="space-y-4">
              <input value={nome} onChange={e => setNome(e.target.value)} placeholder="Nome do Torneio" className="w-full bg-ef-dark p-3 rounded border border-gray-700 focus:border-ef-green" />
              <input type="number" value={qtdTimes} onChange={e => setQtdTimes(e.target.value)} placeholder="Qtd Times" className="w-full bg-ef-dark p-3 rounded border border-gray-700 focus:border-ef-green" />
              <button className="w-full py-3 bg-ef-green text-black font-bold rounded-lg hover:bg-green-400 transition">Criar Agora</button>
            </form>
          </div>
        )}
      </main>
    </div>
  );
}

export default App;
